'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { useCart } from '@/contexts/CartContext';
import { PRODUCTS } from '@/data/products';
import { Product } from '@/types/shop';

export default function ProductDetail({ productId }: { productId: string }) {
  const [product, setProduct] = useState<Product | null>(null);
  const [quantity, setQuantity] = useState(1);
  const { addItem } = useCart();

  useEffect(() => {
    const foundProduct = PRODUCTS.find(p => p.id === productId);
    setProduct(foundProduct || null);
  }, [productId]);

  const handleAddToCart = () => {
    if (product) {
      addItem(product.id, quantity, product.price);
      alert('Product toegevoegd aan winkelwagen!');
    }
  };

  if (!product) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <h2 className="text-2xl font-bold text-gray-900 mb-4">Product niet gevonden</h2>
          <Link href="/shop" className="text-blue-600 hover:underline">
            Terug naar shop
          </Link>
        </div>
      </div>
    );
  }

  const productIcon = 
    product.category === 'onderhoud-reiniging' ? '🧴' :
    product.category === 'tochtwering-isolatie' ? '🔧' :
    product.category === 'raam-accessoires' ? '🪟' :
    product.category === 'deur-accessoires' ? '🚪' :
    '📦';

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="container mx-auto px-4 py-8">
        {/* Breadcrumb */}
        <nav className="mb-8 text-sm">
          <Link href="/" className="text-blue-600 hover:underline">Home</Link>
          <span className="mx-2 text-gray-400">/</span>
          <Link href="/shop" className="text-blue-600 hover:underline">Shop</Link>
          <span className="mx-2 text-gray-400">/</span>
          <span className="text-gray-600">{product.name}</span>
        </nav>

        <div className="grid md:grid-cols-2 gap-12">
          {/* Image */}
          <div>
            <div className="bg-white rounded-lg shadow-lg p-8 mb-4">
              <div className="w-full h-96 flex items-center justify-center bg-gradient-to-br from-blue-50 to-gray-100 rounded-lg">
                <div className="text-9xl">{productIcon}</div>
              </div>
            </div>
            {product.bestseller && (
              <div className="bg-orange-100 border border-orange-300 rounded-lg p-4 text-center">
                <span className="text-orange-800 font-bold">⭐ BESTSELLER</span>
              </div>
            )}
          </div>

          {/* Product Info */}
          <div>
            {product.brand && (
              <div className="text-sm text-gray-500 mb-2">{product.brand}</div>
            )}
            <h1 className="text-3xl font-bold text-gray-900 mb-4">
              {product.name}
            </h1>

            <div className="flex items-center gap-4 mb-6">
              {product.originalPrice ? (
                <div>
                  <span className="text-2xl text-gray-400 line-through mr-3">
                    €{product.originalPrice.toFixed(2)}
                  </span>
                  <span className="text-4xl font-bold text-red-600">
                    €{product.price.toFixed(2)}
                  </span>
                  <span className="ml-3 bg-red-100 text-red-800 px-3 py-1 rounded-full text-sm font-medium">
                    Bespaar €{(product.originalPrice - product.price).toFixed(2)}
                  </span>
                </div>
              ) : (
                <span className="text-4xl font-bold text-blue-600">
                  €{product.price.toFixed(2)}
                </span>
              )}
            </div>

            {product.inStock ? (
              <div className="bg-green-100 text-green-800 px-4 py-2 rounded-lg inline-block mb-6">
                ✓ Op voorraad ({product.stockQuantity} stuks beschikbaar)
              </div>
            ) : (
              <div className="bg-red-100 text-red-800 px-4 py-2 rounded-lg inline-block mb-6">
                Tijdelijk uitverkocht
              </div>
            )}

            <div className="bg-white rounded-lg shadow-md p-6 mb-6">
              <h2 className="font-bold text-lg mb-3">Productomschrijving</h2>
              <p className="text-gray-700 leading-relaxed mb-4">{product.description}</p>
              
              {product.features && product.features.length > 0 && (
                <div className="mt-4">
                  <h3 className="font-semibold mb-2">Kenmerken:</h3>
                  <ul className="space-y-2">
                    {product.features.map((feature, index) => (
                      <li key={index} className="flex items-start">
                        <span className="text-green-600 mr-2">✓</span>
                        <span className="text-gray-700">{feature}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              )}
            </div>

            {/* Specifications */}
            {product.specifications && Object.keys(product.specifications).length > 0 && (
              <div className="bg-white rounded-lg shadow-md p-6 mb-6">
                <h2 className="font-bold text-lg mb-3">Specificaties</h2>
                <dl className="space-y-2">
                  {Object.entries(product.specifications).map(([key, value]) => (
                    <div key={key} className="flex justify-between py-2 border-b border-gray-100">
                      <dt className="text-gray-600">{key}</dt>
                      <dd className="font-medium text-gray-900">{value}</dd>
                    </div>
                  ))}
                  {product.weight && (
                    <div className="flex justify-between py-2 border-b border-gray-100">
                      <dt className="text-gray-600">Gewicht</dt>
                      <dd className="font-medium text-gray-900">{product.weight}g</dd>
                    </div>
                  )}
                  {product.sku && (
                    <div className="flex justify-between py-2">
                      <dt className="text-gray-600">SKU</dt>
                      <dd className="font-medium text-gray-900">{product.sku}</dd>
                    </div>
                  )}
                </dl>
              </div>
            )}

            {/* Add to Cart */}
            <div className="bg-white rounded-lg shadow-md p-6">
              <div className="flex items-center gap-4 mb-4">
                <label className="font-medium text-gray-700">Aantal:</label>
                <div className="flex items-center border border-gray-300 rounded-lg">
                  <button
                    onClick={() => setQuantity(Math.max(1, quantity - 1))}
                    className="px-4 py-2 hover:bg-gray-100 transition-colors"
                  >
                    -
                  </button>
                  <input
                    type="number"
                    value={quantity}
                    onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
                    className="w-16 text-center border-x border-gray-300 py-2"
                    min="1"
                  />
                  <button
                    onClick={() => setQuantity(quantity + 1)}
                    className="px-4 py-2 hover:bg-gray-100 transition-colors"
                  >
                    +
                  </button>
                </div>
              </div>

              <button
                onClick={handleAddToCart}
                disabled={!product.inStock}
                className="w-full bg-blue-600 text-white py-4 rounded-lg font-bold text-lg hover:bg-blue-700 transition-colors disabled:bg-gray-300 disabled:cursor-not-allowed mb-4"
              >
                {product.inStock ? 'Toevoegen aan winkelwagen' : 'Uitverkocht'}
              </button>

              <Link
                href="/shop"
                className="block w-full text-center text-blue-600 hover:underline mb-4"
              >
                ← Terug naar shop
              </Link>

              <div className="mt-4 space-y-2 text-sm text-gray-600 border-t pt-4">
                <p>✓ Gratis verzending vanaf €50</p>
                <p>✓ 14 dagen retourrecht</p>
                <p>✓ Veilig betalen</p>
                <p>✓ Besteld voor 15:00, morgen in huis</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
